import * as React from 'react';
import { graphql } from 'gatsby';
import useIntlHelper from '~src/_i18n/helpers/useIntlHelper';
import Layout from '~src/components/Layout/Layout';

import Link from '~src/_i18n/components/Link';
import ImgSharp from '~src/components/utils/ImgSharp/ImgSharp';
import Subscribe from '~src/components/Layout/Subscribe/SubscribeFooter';
//import ReadNext from '~src/components/Sections/Posts/ReadNext/ReadNext';
import { MarkdownContent } from '~src/components/MarkdownContent/MarkdownContent';
import * as styles from './film.module.scss';
import { Film } from '~src/templates/__generated__/Film';

const FilmTemplate: React.FC<{ data: Film }> = ({ data }) => {
	const stickyRef: React.RefObject<HTMLDivElement> = React.useRef(null);
	const { formatDate, formatMessage } = useIntlHelper();
	return (
		<Layout template="post" stickyRef={stickyRef} data={data}>
			<div className="inner">
				<article className={styles.kgWidthFull}>
					<header className={styles.postFullHeader}>
						<div className={styles.filmMeta}>
							{data.post.frontmatter.tags && (
								<section className={styles.postFullTags}>
									<Link to={`/tags/${data.post.frontmatter.tags[0]}/`}>
										{formatMessage('tags.' + data.post.frontmatter.tags[0] + '.title')}
									</Link>
								</section>
							)}

							<h1 ref={stickyRef} className={styles.postFullTitle}>
								{data.post.frontmatter.title}
							</h1>
							<figure className={styles.filmFullImage}>
								<ImgSharp
									className={styles.kgCodeCard}
									image={data.post.frontmatter.image.childImageSharp.gatsbyImageData}
									alt={data.post.frontmatter.title}
								/>
							</figure>
							{/* 	{post.excerpt && <p className={styles.postFullCustomExcerpt}>{post.excerpt}</p>}	 */}
							<div className={styles.postFullByline}>
								<section className={styles.postFullBylineContent}>
									{/* 	<AuthorList authors={post.frontmatter.authors} isPost={true} />
									 */}
									<section className={styles.postFullBylineMeta}>
										<h3 className="author-name">
											{formatMessage(`projects.director`)} :{data.post.frontmatter.director}
											{/* {post.frontmatter.authors.map((author, i) => (
									<React.Fragment key={i}>
										<Link to={`/authors/${author.id}/`}>{formatMessage(`authors.${author.id}.title`)}</Link>
										{i !== post.frontmatter.authors.length - 1 && formatMessage(`posts.seperator`) + ' '}
									</React.Fragment>
								))}*/}
										</h3>
										<div /* className={styles.postFullBylineMeta} */>
											{formatMessage(`projects.release`)}:
											<time className={styles.postFullMetaDate} dateTime={data.post.frontmatter.release}>
												{formatDate(data.post.frontmatter.release)}
											</time>
										</div>
									</section>
								</section>
							</div>
						</div>
					</header>

					<MarkdownContent body={data.post.body} />
				</article>
				<Subscribe />
			</div>
		</Layout>
	);
};

export default FilmTemplate;

export const PostTemplateQuery = graphql`
	query Film($title: String!, $locale: String!) {
		post: mdx(frontmatter: { title: { eq: $title } }, fields: { locale: { eq: $locale } }) {
			frontmatter {
				title
				release
				director
				tags
				image {
					childImageSharp {
						gatsbyImageData(layout: CONSTRAINED, placeholder: TRACED_SVG)
					}
				}
			}
			excerpt(truncate: true, pruneLength: 200)
			timeToRead
			body
		}
	}
`;
